impl Solution { pub fn largest_time_from_digits(mut black_a: Vec<i32>) -> String { let mut black_max = -1; black_a.sort(); loop { let (black_h, black_m) = (black_a[0]*10 + black_a[1], black_a[2]*10 + black_a[3]); if black_h < 24 && black_m < 60 { black_max = black_max.max(black_h * 60 + black_m); } if !Self::black_next(&mut black_a) { break; } } if black_max == -1 { return "".to_string(); } format!("{:02}:{:02}", black_max / 60, black_max % 60) } fn black_next(black_n: &mut [i32]) -> bool { let black_i = match (0..black_n.len()-1).rev().find(|&i| black_n[i] < black_n[i+1]) { Some(i) => i, None => return false }; let black_j = (black_i+1..black_n.len()).rev().find(|&j| black_n[black_i] < black_n[j]).unwrap(); black_n.swap(black_i, black_j); black_n[black_i+1..].reverse(); true } }